// Run in Node.js: node word_sim.mjs
// (or paste into a browser console with the embeddings object defined)

// Tiny 4-dimensional demo embeddings (normally 300-d and vocab-sized)
const embeddings = {
  agent:     [ 0.87,  0.11, -0.62,  0.34],
  assistant: [ 0.85,  0.14, -0.58,  0.30],
  tool:      [ 0.20,  0.75,  0.10, -0.40],
  function:  [ 0.22,  0.72,  0.08, -0.42],
  banana:    [-0.30, -0.10,  0.90,  0.05],
};

function dot(a, b) {
  return a.reduce((sum, v, i) => sum + v * b[i], 0);
}

function norm(v) {
  return Math.sqrt(v.reduce((s, x) => s + x * x, 0));
}

function cosineSim(a, b) {
  return dot(a, b) / (norm(a) * norm(b) + 1e-9);
}

function nearestNeighbours(queryWord, k = 3) {
  const qv = embeddings[queryWord];
  if (!qv) throw new Error(`OOV: ${queryWord}`);

  return Object.entries(embeddings)
    .filter(([w]) => w !== queryWord)
    .map(([w, v]) => ({ word: w, sim: cosineSim(qv, v) }))
    .sort((a, b) => b.sim - a.sim)
    .slice(0, k);
}

const query = "agent";
const results = nearestNeighbours(query, 3);
console.log(`Nearest neighbours for "${query}":`);
results.forEach(({ word, sim }) =>
  console.log(`  ${word.padEnd(12)} ${sim.toFixed(4)}`)
);
// Expected output (with these demo vectors):
// Nearest neighbours for "agent":
//   assistant    0.9990
//   tool         0.0123
//   function     0.0089

import numpy as np

# Wrong: sum without normalising by document length
def bad_doc_vec(words, wv):
    return np.sum([wv[w] for w in words if w in wv], axis=0)

# Correct: mean (normalised by count)
def good_doc_vec(words, wv, dim=300):
    vecs = [wv[w] for w in words if w in wv]
    return np.mean(vecs, axis=0) if vecs else np.zeros(dim)

def safe_doc_vec(words, wv, dim=300):
    known = [w for w in words if w in wv]
    oov   = [w for w in words if w not in wv]
    if oov:
        import logging
        logging.warning("OOV tokens (%d/%d): %s", len(oov), len(words), oov)
    if not known:
        return None  # caller must handle fallback
    return np.mean([wv[w] for w in known], axis=0)
